// SecureErrorLogger.java - Server-side detailed logging
// ============================================
package com.example.secure;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;

import java.io.PrintWriter;
import java.io.StringWriter;
import java.util.Map;

/**
 * Logs full error details server-side only. These details NEVER leave the server.
 * Use correlation IDs to look up details in logs for debugging.
 */
public final class SecureErrorLogger {

    private static final Logger logger = LoggerFactory.getLogger(SecureErrorLogger.class);

    private SecureErrorLogger() {}

    /**
     * Logs complete error details server-side with correlation ID.
     * This is where stack traces, internal state, and DB errors belong.
     */
    public static void logError(String correlationId,
                                 String operation,
                                 Throwable throwable,
                                 Map<String, String> context) {
        try {
            MDC.put("correlation_id", correlationId);
            MDC.put("operation", operation);

            StringBuilder sb = new StringBuilder();
            sb.append("ERROR [correlation_id=").append(correlationId).append("] ");
            sb.append("operation=").append(operation).append(" ");

            if (context != null) {
                // Sanitize context values before logging to prevent log injection
                for (Map.Entry<String, String> entry : context.entrySet()) {
                    String sanitizedKey = sanitizeLogValue(entry.getKey());
                    String sanitizedValue = sanitizeLogValue(entry.getValue());
                    sb.append(sanitizedKey).append("=").append(sanitizedValue).append(" ");
                }
            }

            if (throwable != null) {
                StringWriter sw = new StringWriter();
                throwable.printStackTrace(new PrintWriter(sw));
                sb.append("\nFull stack trace:\n").append(sw.toString());
            }

            logger.error(sb.toString(), throwable);
        } finally {
            MDC.remove("correlation_id");
            MDC.remove("operation");
        }
    }

    public static void logDatabaseError(String correlationId,
                                         String operation,
                                         String query,
                                         Throwable throwable) {
        try {
            MDC.put("correlation_id", correlationId);
            MDC.put("operation", operation);

            // Log full DB error details server-side for debugging
            logger.error("DATABASE ERROR [correlation_id={}] operation={} " +
                            "sql_state={} error_message={} query_hint={}",
                    correlationId,
                    operation,
                    extractSqlState(throwable),
                    throwable.getMessage(),
                    sanitizeLogValue(query),
                    throwable);
        } finally {
            MDC.remove("correlation_id");
            MDC.remove("operation");
        }
    }

    private static String extractSqlState(Throwable throwable) {
        if (throwable instanceof java.sql.SQLException) {
            return ((java.sql.SQLException) throwable).getSQLState();
        }
        return "UNKNOWN";
    }

    /**
     * Prevents log injection attacks by sanitizing values written to logs.
     */
    private static String sanitizeLogValue(String value) {
        if (value == null) return "null";
        return value.replaceAll("[\\r\\n]", "_")
                    .replaceAll("[^\\x20-\\x7E]", "_");
    }
}

