package com.example.secure;

import java.sql.SQLException;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class UserRepository {

    private final Map<String, String[]> users = new ConcurrentHashMap<>();

    public UserRepository() {
        users.put("user-1", new String[]{"Alice Smith", "alice@example.com"});
        users.put("user-2", new String[]{"Bob Jones", "bob@example.com"});
    }

    public String[] findById(String userId) throws SQLException {
        // Simulate potential database errors
        if ("error-trigger".equals(userId)) {
            throw new SQLException(
                    "Connection refused to host: db-primary-01.internal:5432 " +
                    "- password authentication failed for user 'app_service'",
                    "28P01", 1045);
        }
        return users.get(userId);
    }

    public String create(String name, String email) throws SQLException {
        // Check for duplicates
        for (Map.Entry<String, String[]> entry : users.entrySet()) {
            if (entry.getValue()[1].equalsIgnoreCase(email)) {
                throw new SQLException(
                        "ERROR: duplicate key value violates unique constraint \"users_email_key\" " +
                        "Detail: Key (email)=(" + email + ") already exists. " +
                        "Schema: public, Table: users, Constraint: users_email_key",
                        "23505", 0);
            }
        }

        String id = "user-" + (users.size() + 1);
        users.put(id, new String[]{name, email});
        return id;
    }
}

