package com.example.secure;

import com.example.secure.proto.CreateUserRequest;
import com.example.secure.proto.CreateUserResponse;
import com.example.secure.proto.GetUserRequest;
import com.example.secure.proto.GetUserResponse;
import com.example.secure.proto.UserServiceGrpc;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.SQLException;
import java.util.HashMap;
import java.util.Map;

public class UserServiceImpl extends UserServiceGrpc.UserServiceImplBase {

    private static final Logger logger = LoggerFactory.getLogger(UserServiceImpl.class);
    private final UserRepository userRepository;

    public UserServiceImpl(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Override
    public void getUser(GetUserRequest request, StreamObserver<GetUserResponse> responseObserver) {
        String correlationId = ErrorCorrelation.generate();

        try {
            // Validate input
            String validationError = InputValidator.validateUserId(request.getUserId());
            if (validationError != null) {
                throw SanitizedErrorDetails.invalidArgument(correlationId, "user_id", validationError);
            }

            // Attempt data access
            String[] userData = userRepository.findById(request.getUserId());

            if (userData == null) {
                // Log the lookup details server-side
                SecureErrorLogger.logError(correlationId, "getUser",
                        null,
                        Map.of("user_id", request.getUserId(), "result", "NOT_FOUND"));

                // Return safe error to client
                responseObserver.onError(
                        SanitizedErrorDetails.notFound(correlationId, "user"));
                return;
            }

            GetUserResponse response = GetUserResponse.newBuilder()
                    .setUserId(request.getUserId())
                    .setName(userData[0])
                    .setEmail(userData[1])
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();

        } catch (SQLException e) {
            // *** SECURE: Log full DB error server-side, return safe message to client ***
            SecureErrorLogger.logDatabaseError(correlationId, "getUser",
                    "SELECT * FROM users WHERE id = ?", e);

            // Client gets correlation ID only - NO SQL state, NO error message, NO stack trace
            responseObserver.onError(
                    SanitizedErrorDetails.dataAccessError(correlationId));

        } catch (io.grpc.StatusRuntimeException e) {
            // Re-throw gRPC errors we created (validation errors, not found, etc.)
            responseObserver.onError(e);

        } catch (Exception e) {
            // *** SECURE: Catch-all logs everything server-side ***
            Map<String, String> context = new HashMap<>();
            context.put("user_id", request.getUserId());
            context.put("exception_class", e.getClass().getName());

            SecureErrorLogger.logError(correlationId, "getUser", e, context);

            // Client gets generic error with correlation ID only
            responseObserver.onError(
                    SanitizedErrorDetails.internal(correlationId));
        }
    }

    @Override
    public void createUser(CreateUserRequest request, StreamObserver<CreateUserResponse> responseObserver) {
        String correlationId = ErrorCorrelation.generate();

        try {
            // Validate inputs
            String nameError = InputValidator.validateName(request.getName());
            if (nameError != null) {
                responseObserver.onError(
                        SanitizedErrorDetails.invalidArgument(correlationId, "name", nameError));
                return;
            }

            String emailError = InputValidator.validateEmail(request.getEmail());
            if (emailError != null) {
                responseObserver.onError(
                        SanitizedErrorDetails.invalidArgument(correlationId, "email", emailError));
                return;
            }

            String userId = userRepository.create(request.getName(), request.getEmail());

            CreateUserResponse response = CreateUserResponse.newBuilder()
                    .setUserId(userId)
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();

        } catch (SQLException e) {
            // *** SECURE: Full DB error logged server-side ***
            SecureErrorLogger.logDatabaseError(correlationId, "createUser",
                    "INSERT INTO users (name, email) VALUES (?, ?)", e);

            // Determine safe client response based on SQL state
            if ("23505".equals(e.getSQLState())) {
                // Unique constraint violation - safe to tell client it's a duplicate
                // but NOT safe to expose the constraint name, schema, or table
                responseObserver.onError(
                        SanitizedErrorDetails.alreadyExists(correlationId, "user"));
            } else {
                responseObserver.onError(
                        SanitizedErrorDetails.dataAccessError(correlationId));
            }

        } catch (Exception e) {
            Map<String, String> context = new HashMap<>();
            context.put("operation", "createUser");
            context.put("exception_class", e.getClass().getName());

            SecureErrorLogger.logError(correlationId, "createUser", e, context);

            responseObserver.onError(
                    SanitizedErrorDetails.internal(correlationId));
        }
    }
}

