// GlobalExceptionInterceptor.java - Server interceptor for uncaught errors
// ============================================
package com.example.secure;

import io.grpc.ForwardingServerCallListener.SimpleForwardingServerCallListener;
import io.grpc.ForwardingServerCall.SimpleForwardingServerCall;
import io.grpc.Metadata;
import io.grpc.ServerCall;
import io.grpc.ServerCallHandler;
import io.grpc.ServerInterceptor;
import io.grpc.Status;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.Map;

/**
 * Global interceptor that catches any unhandled exceptions and ensures
 * they NEVER leak internal details to clients.
 */
public class GlobalExceptionInterceptor implements ServerInterceptor {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionInterceptor.class);

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        ServerCall<ReqT, RespT> wrappedCall = new SimpleForwardingServerCall<ReqT, RespT>(call) {
            @Override
            public void close(Status status, Metadata trailers) {
                if (status.getCode() == Status.Code.UNKNOWN && status.getCause() != null) {
                    // An unhandled exception escaped - sanitize it
                    String correlationId = ErrorCorrelation.generate();

                    SecureErrorLogger.logError(correlationId,
                            call.getMethodDescriptor().getFullMethodName(),
                            status.getCause(),
                            Map.of("interceptor", "GlobalExceptionInterceptor",
                                   "original_status", status.getCode().name()));

                    // Replace with safe status - NO exception details
                    Status safeStatus = Status.INTERNAL
                            .withDescription("Internal error. Correlation ID: " + correlationId);
                    super.close(safeStatus, trailers);
                } else {
                    super.close(status, trailers);
                }
            }
        };

        ServerCall.Listener<ReqT> listener = next.startCall(wrappedCall, headers);

        return new SimpleForwardingServerCallListener<ReqT>(listener) {
            @Override
            public void onHalfClose() {
                try {
                    super.onHalfClose();
                } catch (Exception e) {
                    String correlationId = ErrorCorrelation.generate();

                    SecureErrorLogger.logError(correlationId,
                            call.getMethodDescriptor().getFullMethodName(),
                            e,
                            Map.of("interceptor", "GlobalExceptionInterceptor",
                                   "phase", "onHalfClose"));

                    call.close(Status.INTERNAL
                                    .withDescription("Internal error. Correlation ID: " + correlationId),
                            new Metadata());
                }
            }

            @Override
            public void onMessage(ReqT message) {
                try {
                    super.onMessage(message);
                } catch (Exception e) {
                    String correlationId = ErrorCorrelation.generate();

                    SecureErrorLogger.logError(correlationId,
                            call.getMethodDescriptor().getFullMethodName(),
                            e,
                            Map.of("interceptor", "GlobalExceptionInterceptor",
                                   "phase", "onMessage"));

                    call.close(Status.INTERNAL
                                    .withDescription("Internal error. Correlation ID: " + correlationId),
                            new Metadata());
                }
            }
        };
    }
}

