// SecureGrpcServer.java - Server startup
// ============================================
package com.example.secure;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

public class SecureGrpcServer {

    private static final Logger logger = LoggerFactory.getLogger(SecureGrpcServer.class);
    private static final int PORT = 50051;

    private Server server;

    public void start() throws IOException {
        UserRepository userRepository = new UserRepository();
        UserServiceImpl userService = new UserServiceImpl(userRepository);

        server = ServerBuilder.forPort(PORT)
                .addService(userService)
                .intercept(new GlobalExceptionInterceptor())
                .maxInboundMessageSize(4 * 1024 * 1024) // 4MB limit
                .build()
                .start();

        logger.info("Secure gRPC server started on port {}", PORT);

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            logger.info("Shutting down gRPC server...");
            try {
                SecureGrpcServer.this.stop();
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                logger.error("Server shutdown interrupted", e);
            }
        }));
    }

    public void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        SecureGrpcServer server = new SecureGrpcServer();
        server.start();
        server.blockUntilShutdown();
    }
}

