// SecureGrpcClient.java - Demo client showing what clients actually receive
// ============================================
package com.example.secure;

import com.google.protobuf.Any;
import com.google.protobuf.InvalidProtocolBufferException;
import com.google.rpc.ErrorInfo;
import com.google.rpc.BadRequest;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;
import com.example.secure.proto.GetUserRequest;
import com.example.secure.proto.GetUserResponse;
import com.example.secure.proto.CreateUserRequest;
import com.example.secure.proto.CreateUserResponse;
import com.example.secure.proto.UserServiceGrpc;

import java.util.concurrent.TimeUnit;

public class SecureGrpcClient {

    public static void main(String[] args) throws InterruptedException {
        ManagedChannel channel = ManagedChannelBuilder.forAddress("localhost", 50051)
                .usePlaintext() // For demo only - use TLS in production
                .build();

        UserServiceGrpc.UserServiceBlockingStub stub = UserServiceGrpc.newBlockingStub(channel);

        // Test 1: Successful request
        System.out.println("=== Test 1: Successful GetUser ===");
        try {
            GetUserResponse response = stub.getUser(
                    GetUserRequest.newBuilder().setUserId("user-1").build());
            System.out.println("Success: " + response.getName() + " - " + response.getEmail());
        } catch (StatusRuntimeException e) {
            printSafeError(e);
        }

        // Test 2: Not found
        System.out.println("\n=== Test 2: User Not Found ===");
        try {
            stub.getUser(GetUserRequest.newBuilder().setUserId("nonexistent").build());
        } catch (StatusRuntimeException e) {
            printSafeError(e);
            // Notice: NO stack trace, NO internal state, NO DB details
        }

        // Test 3: Invalid input
        System.out.println("\n=== Test 3: Invalid Input ===");
        try {
            stub.getUser(GetUserRequest.newBuilder().setUserId("").build());
        } catch (StatusRuntimeException e) {
            printSafeError(e);
        }

        // Test 4: Database error (simulated)
        System.out.println("\n=== Test 4: Database Error ===");
        try {
            stub.getUser(GetUserRequest.newBuilder().setUserId("error-trigger").build());
        } catch (StatusRuntimeException e) {
            printSafeError(e);
            // Notice: Client sees "Service temporarily unavailable" NOT the SQL error
        }

        // Test 5: Duplicate creation
        System.out.println("\n=== Test 5: Duplicate Email ===");
        try {
            stub.createUser(CreateUserRequest.newBuilder()
                    .setName("Alice Clone")
                    .setEmail("alice@example.com")
                    .build());
        } catch (StatusRuntimeException e) {
            printSafeError(e);
            // Notice: Client sees "already exists" NOT the constraint name or schema
        }

        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    /**
     * Demonstrates what the CLIENT receives - safe, actionable error info
     * with correlation IDs for support escalation.
     */
    private static void printSafeError(StatusRuntimeException e) {
        System.out.println("Status: " + e.getStatus().getCode());
        System.out.println("Message: " + e.getStatus().getDescription());

        // Extract rich error details
        com.google.rpc.Status rpcStatus = StatusProto.fromThrowable(e);
        if (rpcStatus != null) {
            for (Any detail : rpcStatus.getDetailsList()) {
                try {
                    if (detail.is(ErrorInfo.class)) {
                        ErrorInfo errorInfo = detail.unpack(ErrorInfo.class);
                        System.out.println("Reason: " + errorInfo.getReason());
                        System.out.println("Correlation ID: " +
                                errorInfo.getMetadataMap().get("correlation_id"));
                        System.out.println("(Use this ID when contacting support)");
                    } else if (detail.is(BadRequest.class)) {
                        BadRequest badRequest = detail.unpack(BadRequest.class);
                        for (BadRequest.FieldViolation fv : badRequest.getFieldViolationsList()) {
                            System.out.println("Field error - " + fv.getField() +
                                    ": " + fv.getDescription());
                        }
                    }
                } catch (InvalidProtocolBufferException ex) {
                    System.out.println("Could not parse error detail");
                }
            }
        }
    }
}